mapper.select:
SELECT COUNT(DISTINCT p.project_id) FROM pm_project p LEFT JOIN sys_dept d ON CAST(p.project_dept AS CHAR) COLLATE utf8mb4_unicode_ci = CAST(d.dept_id AS CHAR) LEFT JOIN sys_user u_create ON p.create_by COLLATE utf8mb4_unicode_ci = u_create.user_name WHERE p.del_flag = '0'
AND p.project_name LIKE CONCAT('%', #{projectName}, '%')
${params.dataScope}
